type Story = StoryObj;

const styles = html`
  <style>
    .ty-spec-doc {
      box-sizing: border-box;
      max-width: 920px;
      padding: 32px;
      color: CanvasText;
      font: 14px/1.55 system-ui, sans-serif;
    }

    .ty-spec-doc h1,
    .ty-spec-doc h2,
    .ty-spec-doc h3 {
      line-height: 1.2;
    }

    .ty-spec-doc h1 {
      margin: 0 0 20px;
      font-size: 28px;
    }

    .ty-spec-doc h2 {
      margin: 28px 0 12px;
      font-size: 20px;
    }

    .ty-spec-doc h3 {
      margin: 22px 0 10px;
      font-size: 16px;
    }

    .ty-spec-doc table {
      width: 100%;
      border-collapse: collapse;
      margin: 14px 0 22px;
      font-size: 13px;
    }

    .ty-spec-doc th,
    .ty-spec-doc td {
      border: 1px solid color-mix(in srgb, CanvasText 18%, Canvas);
      padding: 8px 10px;
      text-align: start;
      vertical-align: top;
    }

    .ty-spec-doc th {
      background: color-mix(in srgb, CanvasText 6%, Canvas);
      font-weight: 650;
    }

    .ty-spec-doc code {
      font-family: ui-monospace, SFMono-Regular, Menlo, Consolas, monospace;
      font-size: 0.92em;
    }

    .ty-spec-doc pre {
      overflow: auto;
      padding: 14px;
      border: 1px solid color-mix(in srgb, CanvasText 18%, Canvas);
      border-radius: 6px;
      background: color-mix(in srgb, CanvasText 5%, Canvas);
    }

    .ty-spec-example {
      display: grid;
      gap: 12px;
      margin: 0 0 28px;
    }

    .ty-spec-example-preview {
      padding: 18px;
      border: 1px solid color-mix(in srgb, CanvasText 16%, Canvas);
      border-radius: 6px;
    }
  </style>
`;

function markdownPage(markdown: string) {
  return html`<article class="ty-spec-doc">${styles}${unsafeHTML(markdown)}</article>`;
}

function examplesPage() {
  return html`<article class="ty-spec-doc">
    ${styles}
    <h1>Input Examples</h1>
    ${examples.length > 0
      ? examples.map(renderExample)
      : html`<p>No Storybook examples are marked in the component spec yet.</p>`}
  </article>`;
}

function designsPage() {
  return html`<article class="ty-spec-doc">
    ${styles}
    <h1>Input Designs</h1>
    ${designs.length > 0
      ? designs.map(renderExample)
      : html`<p>No design examples are marked in the component spec yet.</p>`}
  </article>`;
}

function renderExample(example: { title: string; code: string }) {
  return html`<section class="ty-spec-example">
    <h2>${example.title}</h2>
    <div class="ty-spec-example-preview">${unsafeHTML(example.code)}</div>
    <pre><code>${example.code}</code></pre>
  </section>`;
}

export const About: Story = {
  render: () => markdownPage("<h1>Input</h1>\n<h2>Identity</h2>\n<ul>\n<li>Component name: Input</li>\n<li>Tag name: <code>tyui-input</code></li>\n<li>Package entry point: <code>@toyu-ui/elements/input</code></li>\n<li>Status: Draft</li>\n<li>Source file: <code>libs/elements/src/input/input.ts</code></li>\n<li>Manifest reference: <code>custom-elements.json#/modules/.../declarations/TyuiInput</code></li>\n<li>Design metadata file: <code>libs/elements/src/input/input.design.json</code></li>\n<li>Component family: Form field</li>\n<li>Pattern type: Native text input wrapper</li>\n<li>Closest native element or ARIA pattern: <code>&lt;input&gt;</code> with implicit textbox/searchbox/spinbutton semantics depending on type</li>\n<li>Fluent / reference analogue: Fluent UI v9 <code>Input</code>; Teams MCP <code>&lt;ds-input&gt;</code></li>\n<li>Related components: future <code>tyui-field</code>, <code>tyui-textarea</code>, <code>tyui-search-box</code>, <code>tyui-select</code>, <code>tyui-combobox</code></li>\n</ul>\n<h2>Intent</h2>\n<p>Use <code>tyui-input</code> for single-line text entry where users type short freeform values such as names, email addresses, URLs, search terms, telephone numbers, passwords, or numeric text.</p>\n<p>Do not use it for multiline text; use <code>tyui-textarea</code>. Do not use it for rich option picking; use select, combobox, or tag picker patterns. Do not use placeholder text as the only label.</p>\n<h2>Selection Guidance</h2>\n<ul>\n<li>Use when: a single-line native text input is the right semantic control.</li>\n<li>Do not use when: the value is multiline, selected from a constrained list, date/time-like, color-like, or requires custom option rendering.</li>\n<li>Prefer instead: <code>tyui-textarea</code> for multiline text, <code>tyui-select</code> for simple native single choice, <code>tyui-combobox</code> for richer listbox behavior, future date/time pickers for date/time values, <code>tyui-search-box</code> for search with clear affordance.</li>\n<li>Product-level variant preferences: product <code>design-app.md</code> may prefer one default appearance and size, but must keep accessible labeling and contrast requirements.</li>\n<li>One semantic target / one action rule: the input edits text only. Icons in content slots are decorative unless a future specialized component exposes separate clear/search actions.</li>\n</ul>"),
};

export const API: Story = {
  render: () => markdownPage("<h1>Input API</h1>\n<h2>API</h2>\n<h3>Attributes</h3>\n<table><thead><tr><th>Name</th><th>Type</th><th>Reflected Property</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>appearance</code></td><td><code>outline | filled-darker | filled-lighter</code></td><td><code>appearance</code></td><td><code>outline</code></td><td>Base field style. Fluent underline is a design-system variant, not a base component appearance.</td></tr><tr><td><code>default-value</code></td><td><code>string</code></td><td><code>defaultValue</code></td><td><code>''</code></td><td>Seeds <code>value</code> once on first connection when <code>value</code> is empty. Later changes do not overwrite current value.</td></tr><tr><td><code>disabled</code></td><td><code>boolean</code></td><td><code>disabled</code></td><td><code>false</code></td><td>Disables the internal native input.</td></tr><tr><td><code>invalid</code></td><td><code>boolean</code></td><td><code>invalid</code></td><td><code>false</code></td><td>Reflected visual/ARIA invalid state. Also set by required validity sync.</td></tr><tr><td><code>name</code></td><td><code>string</code></td><td><code>name</code></td><td><code>''</code></td><td>Form field name used by ElementInternals.</td></tr><tr><td><code>placeholder</code></td><td><code>string</code></td><td><code>placeholder</code></td><td><code>''</code></td><td>Placeholder forwarded to native input; not a label substitute.</td></tr><tr><td><code>readonly</code></td><td><code>boolean</code></td><td><code>readonly</code></td><td><code>false</code></td><td>Forwards to native <code>readOnly</code>; focusable and selectable, but user edits do not mutate value.</td></tr><tr><td><code>required</code></td><td><code>boolean</code></td><td><code>required</code></td><td><code>false</code></td><td>Forwards to native input and drives ElementInternals <code>valueMissing</code>.</td></tr><tr><td><code>size</code></td><td><code>small | medium | large</code></td><td><code>size</code></td><td><code>medium</code></td><td>Field density and typography.</td></tr><tr><td><code>type</code></td><td><code>text | email | password | search | tel | url | number</code></td><td><code>type</code></td><td><code>text</code></td><td>Native input type subset. Date/time types are intentionally excluded.</td></tr><tr><td><code>value</code></td><td><code>string</code></td><td><code>value</code></td><td><code>''</code></td><td>Initial value when authored as an attribute; property is authoritative after upgrade.</td></tr></tbody></table>\n<h3>Properties</h3>\n<table><thead><tr><th>Name</th><th>Type</th><th>Attribute</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>appearance</code></td><td>same as attribute</td><td><code>appearance</code></td><td><code>outline</code></td><td>Reflects to host.</td></tr><tr><td><code>defaultValue</code></td><td><code>string</code></td><td><code>default-value</code></td><td><code>''</code></td><td>Seeds initial value once.</td></tr><tr><td><code>disabled</code></td><td><code>boolean</code></td><td><code>disabled</code></td><td><code>false</code></td><td>Reflects to host and internal input.</td></tr><tr><td><code>invalid</code></td><td><code>boolean</code></td><td><code>invalid</code></td><td><code>false</code></td><td>Reflects to host and should mirror <code>aria-invalid</code> to internal input when true.</td></tr><tr><td><code>name</code></td><td><code>string</code></td><td><code>name</code></td><td><code>''</code></td><td>Used for form submission.</td></tr><tr><td><code>placeholder</code></td><td><code>string</code></td><td><code>placeholder</code></td><td><code>''</code></td><td>Forwarded to internal input.</td></tr><tr><td><code>readonly</code></td><td><code>boolean</code></td><td><code>readonly</code></td><td><code>false</code></td><td>Reflects to host and internal input.</td></tr><tr><td><code>required</code></td><td><code>boolean</code></td><td><code>required</code></td><td><code>false</code></td><td>Reflects to host and internal input.</td></tr><tr><td><code>size</code></td><td><code>small | medium | large</code></td><td><code>size</code></td><td><code>medium</code></td><td>Reflects to host.</td></tr><tr><td><code>type</code></td><td>supported type union</td><td><code>type</code></td><td><code>text</code></td><td>Reflects to host and internal input.</td></tr><tr><td><code>value</code></td><td><code>string</code></td><td><code>value</code></td><td><code>''</code></td><td>Updates internal input and form value. Programmatic writes do not emit <code>input</code> or <code>change</code>.</td></tr></tbody></table>\n<h3>Events</h3>\n<table><thead><tr><th>Name</th><th>Detail Type</th><th>Bubbles</th><th>Composed</th><th>Description</th></tr></thead><tbody><tr><td><code>input</code></td><td><code>CustomEvent&lt;{ value: string }&gt;</code></td><td>yes</td><td>yes</td><td>Fired for user text input after host <code>value</code> updates.</td></tr><tr><td><code>change</code></td><td><code>Event</code></td><td>yes</td><td>yes</td><td>Fired when the native input commits a change.</td></tr></tbody></table>\n<h3>Event Semantics</h3>\n<ul>\n<li>User-initiated events: typing dispatches <code>input</code> with <code>detail.value</code>; native commit dispatches <code>change</code>.</li>\n<li>Programmatic state changes that must not emit user events: setting <code>value</code>, <code>defaultValue</code>, <code>appearance</code>, <code>size</code>, <code>type</code>, <code>disabled</code>, <code>readonly</code>, <code>required</code>, or <code>invalid</code>.</li>\n<li>Native events that are re-dispatched: inner native <code>input</code> is stopped and re-dispatched from the host as <code>CustomEvent</code>; inner <code>change</code> is stopped and re-dispatched from the host as composed <code>Event</code>.</li>\n<li>Internal coordination events: none.</li>\n<li>Cancellation behavior: ordinary text input is native; do not cancel editing keys.</li>\n</ul>\n<h3>Slots</h3>\n<table><thead><tr><th>Name</th><th>Description</th><th>Fallback</th><th>Slotted Styling Rules</th></tr></thead><tbody><tr><td><code>contentBefore</code></td><td>Decorative or supplemental content before typed text, inside the field border.</td><td>none</td><td>Slotted SVG/icons are sized by <code>--_ty-input-icon-size</code> and inherit muted foreground.</td></tr><tr><td><code>contentAfter</code></td><td>Decorative or supplemental content after typed text, inside the field border.</td><td>none</td><td>Must not be focusable in the base input. Use a specialized component for clear buttons.</td></tr></tbody></table>\n<h3>CSS Parts</h3>\n<table><thead><tr><th>Name</th><th>Description</th><th>Allowed Use</th><th>Required State Qualifiers</th></tr></thead><tbody><tr><td><code>control</code></td><td>Wrapper surface around slots and native input.</td><td>Advanced border/background/radius treatment when tokens are insufficient.</td><td>Qualify by host <code>[appearance]</code>, <code>[size]</code>, <code>[invalid]</code>, <code>[disabled]</code>, <code>[readonly]</code>.</td></tr><tr><td><code>input</code></td><td>Internal native <code>&lt;input&gt;</code>.</td><td>Rare typography or input-specific styling.</td><td>Avoid changing semantics or hiding text.</td></tr><tr><td><code>content-before</code></td><td>Wrapper around <code>contentBefore</code> slot.</td><td>Slot wrapper alignment/color adjustments.</td><td>Qualify by host state when needed.</td></tr><tr><td><code>content-after</code></td><td>Wrapper around <code>contentAfter</code> slot.</td><td>Slot wrapper alignment/color adjustments.</td><td>Qualify by host state when needed.</td></tr></tbody></table>\n<h3>Forwarded CSS Parts</h3>\n<table><thead><tr><th>Name</th><th>Source Component</th><th>Description</th></tr></thead><tbody><tr><td>N/A</td><td>N/A</td><td>Base input does not compose nested TYUI components internally.</td></tr></tbody></table>\n<h3>CSS Custom Properties</h3>\n<h4>Public Tokens</h4>\n<table><thead><tr><th>Name</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>--ty-input-background</code></td><td><code>var(--ty-color-surface)</code></td><td>Resting field background.</td></tr><tr><td><code>--ty-input-background-filled-darker</code></td><td><code>var(--ty-color-surface-pressed)</code></td><td>Filled darker background.</td></tr><tr><td><code>--ty-input-background-filled-lighter</code></td><td><code>var(--ty-color-surface-hover)</code></td><td>Filled lighter background.</td></tr><tr><td><code>--ty-input-foreground</code></td><td><code>var(--ty-color-text)</code></td><td>Input text color.</td></tr><tr><td><code>--ty-input-placeholder-color</code></td><td><code>var(--ty-color-text-muted)</code></td><td>Placeholder color.</td></tr><tr><td><code>--ty-input-border-color</code></td><td><code>var(--ty-color-border)</code></td><td>Resting border.</td></tr><tr><td><code>--ty-input-border-color-strong</code></td><td><code>var(--ty-color-border-strong)</code></td><td>Hover/focus-capable border.</td></tr><tr><td><code>--ty-input-invalid-border-color</code></td><td><code>var(--ty-color-danger)</code></td><td>Invalid border.</td></tr><tr><td><code>--ty-input-focus-indicator-color</code></td><td><code>var(--ty-color-accent)</code></td><td>Focus outline color.</td></tr><tr><td><code>--ty-input-radius</code></td><td><code>var(--ty-control-radius)</code></td><td>Control radius.</td></tr><tr><td><code>--ty-input-min-block-size</code></td><td>size-derived token</td><td>Minimum field height.</td></tr><tr><td><code>--ty-input-padding-inline</code></td><td><code>var(--ty-control-padding-inline)</code></td><td>Inline field padding.</td></tr><tr><td><code>--ty-input-padding-block</code></td><td><code>var(--ty-control-padding-block)</code></td><td>Native input block padding.</td></tr><tr><td><code>--ty-input-gap</code></td><td><code>var(--ty-control-gap)</code></td><td>Slot/text gap.</td></tr><tr><td><code>--ty-input-font-size</code></td><td><code>var(--ty-control-font-size)</code></td><td>Text size.</td></tr></tbody></table>\n<h4>Private Implementation Variables</h4>\n<p>Private variables use the <code>--_ty-*</code> prefix. List them only so reviewers can distinguish implementation details from consumer hooks; consumers must not depend on them.</p>\n<table><thead><tr><th>Name</th><th>Purpose</th></tr></thead><tbody><tr><td><code>--_ty-input-icon-size</code></td><td>Size content slot icons per input size.</td></tr></tbody></table>\n<h3>Styling State Surface</h3>\n<table><thead><tr><th>State</th><th>Surface</th><th>Public</th><th>Notes</th></tr></thead><tbody><tr><td>Appearance</td><td>Host <code>[appearance]</code></td><td>Yes</td><td>Drives outline, filled-darker, and filled-lighter.</td></tr><tr><td>Size</td><td>Host <code>[size]</code></td><td>Yes</td><td>Drives min block size, padding, icon size, font size.</td></tr><tr><td>Disabled</td><td>Host <code>[disabled]</code>; internal native <code>disabled</code></td><td>Yes</td><td>Removes editing and normal focus.</td></tr><tr><td>Readonly</td><td>Host <code>[readonly]</code>; internal native <code>readOnly</code></td><td>Yes</td><td>Remains focusable/selectable.</td></tr><tr><td>Required</td><td>Host <code>[required]</code>; internal native <code>required</code></td><td>Yes</td><td>Drives validity.</td></tr><tr><td>Invalid</td><td>Host <code>[invalid]</code>; internal <code>aria-invalid=&quot;true&quot;</code> when true</td><td>Yes</td><td>Can be set directly or by validity sync.</td></tr><tr><td>Focus</td><td><code>:focus-within</code> on control</td><td>Yes through behavior</td><td>Shows neutral focus outline; design layers may restyle documented parts.</td></tr><tr><td>Hover</td><td><code>:hover</code> on control when not disabled</td><td>Yes through behavior</td><td>Visual only.</td></tr></tbody></table>\n<h2>Slots</h2>\n<table><thead><tr><th>Name</th><th>Description</th><th>Fallback</th><th>Slotted Styling Rules</th></tr></thead><tbody><tr><td><code>contentBefore</code></td><td>Decorative or supplemental content before typed text, inside the field border.</td><td>none</td><td>Slotted SVG/icons are sized by <code>--_ty-input-icon-size</code> and inherit muted foreground.</td></tr><tr><td><code>contentAfter</code></td><td>Decorative or supplemental content after typed text, inside the field border.</td><td>none</td><td>Must not be focusable in the base input. Use a specialized component for clear buttons.</td></tr></tbody></table>\n<h2>CSS Parts</h2>\n<table><thead><tr><th>Name</th><th>Description</th><th>Allowed Use</th><th>Required State Qualifiers</th></tr></thead><tbody><tr><td><code>control</code></td><td>Wrapper surface around slots and native input.</td><td>Advanced border/background/radius treatment when tokens are insufficient.</td><td>Qualify by host <code>[appearance]</code>, <code>[size]</code>, <code>[invalid]</code>, <code>[disabled]</code>, <code>[readonly]</code>.</td></tr><tr><td><code>input</code></td><td>Internal native <code>&lt;input&gt;</code>.</td><td>Rare typography or input-specific styling.</td><td>Avoid changing semantics or hiding text.</td></tr><tr><td><code>content-before</code></td><td>Wrapper around <code>contentBefore</code> slot.</td><td>Slot wrapper alignment/color adjustments.</td><td>Qualify by host state when needed.</td></tr><tr><td><code>content-after</code></td><td>Wrapper around <code>contentAfter</code> slot.</td><td>Slot wrapper alignment/color adjustments.</td><td>Qualify by host state when needed.</td></tr></tbody></table>\n<h2>Events</h2>\n<table><thead><tr><th>Name</th><th>Detail Type</th><th>Bubbles</th><th>Composed</th><th>Description</th></tr></thead><tbody><tr><td><code>input</code></td><td><code>CustomEvent&lt;{ value: string }&gt;</code></td><td>yes</td><td>yes</td><td>Fired for user text input after host <code>value</code> updates.</td></tr><tr><td><code>change</code></td><td><code>Event</code></td><td>yes</td><td>yes</td><td>Fired when the native input commits a change.</td></tr></tbody></table>\n<h2>Event Semantics</h2>\n<ul>\n<li>User-initiated events: typing dispatches <code>input</code> with <code>detail.value</code>; native commit dispatches <code>change</code>.</li>\n<li>Programmatic state changes that must not emit user events: setting <code>value</code>, <code>defaultValue</code>, <code>appearance</code>, <code>size</code>, <code>type</code>, <code>disabled</code>, <code>readonly</code>, <code>required</code>, or <code>invalid</code>.</li>\n<li>Native events that are re-dispatched: inner native <code>input</code> is stopped and re-dispatched from the host as <code>CustomEvent</code>; inner <code>change</code> is stopped and re-dispatched from the host as composed <code>Event</code>.</li>\n<li>Internal coordination events: none.</li>\n<li>Cancellation behavior: ordinary text input is native; do not cancel editing keys.</li>\n</ul>"),
};

